changeSet.sql:
INSERT INTO auth_client (client_id, client_secret, client_name, redirect_uris, scopes, grant_types, require_pkce, access_token_ttl, refresh_token_ttl, status)
SELECT 'afg-workspace-ui', NULL, '工作台前端', 'http://localhost:8000/sso/callback', 'read,write', 'authorization_code,refresh_token', true, 7200, 604800, 1
WHERE NOT EXISTS (SELECT 1 FROM auth_client WHERE client_id = 'afg-workspace-ui');

INSERT INTO auth_client (client_id, client_secret, client_name, redirect_uris, scopes, grant_types, require_pkce, access_token_ttl, refresh_token_ttl, status)
SELECT 'afg-keystone-ui', NULL, 'Keystone 管理前端', 'http://localhost:3001/sso/callback', 'read,write', 'authorization_code,refresh_token', true, 7200, 604800, 1
WHERE NOT EXISTS (SELECT 1 FROM auth_client WHERE client_id = 'afg-keystone-ui');

INSERT INTO auth_client (client_id, client_secret, client_name, redirect_uris, scopes, grant_types, require_pkce, access_token_ttl, refresh_token_ttl, status)
SELECT 'afg-ai-ui', NULL, 'AI 平台前端', 'http://localhost:3002/sso/callback', 'read,write', 'authorization_code,refresh_token', true, 7200, 604800, 1
WHERE NOT EXISTS (SELECT 1 FROM auth_client WHERE client_id = 'afg-ai-ui');


INSERT INTO auth_app (name, logo, description, app_type, status, sort_order, active_rule, entry_url, export_path, allowed_origins, client_id)
SELECT 'Keystone', 'setting', '身份管理、服务治理、配置管理', 'mf', 1, 1, '/keystone', 'http://localhost:3001/remoteEntry.js', './export-app', 'http://localhost:3001', 'afg-keystone-ui'
WHERE NOT EXISTS (SELECT 1 FROM auth_app WHERE name = 'Keystone');

INSERT INTO auth_app (name, logo, description, app_type, status, sort_order, active_rule, entry_url, export_path, allowed_origins, client_id)
SELECT 'AI 平台', 'robot', 'AI 对话、技能、知识库管理', 'mf', 1, 2, '/ai', 'http://localhost:3002/remoteEntry.js', './export-app', 'http://localhost:3002', 'afg-ai-ui'
WHERE NOT EXISTS (SELECT 1 FROM auth_app WHERE name = 'AI 平台');
